def _detect_format(data: bytes, source_name: str | None = None) -> str:
    if data.startswith(b"\xFF\xD8"):
        return "jpeg"
    if data.startswith(b"\x89PNG\r\n\x1a\n"):
        return "png"
    if data.startswith(b"GIF87a") or data.startswith(b"GIF89a"):
        return "gif"
    if data.startswith(b"BM"):
        return "bmp"
    if len(data) >= 12 and data[0:4] == b"RIFF" and data[8:12] == b"WEBP":
        return "webp"
    if len(data) >= 4 and data[0:2] in {b"II", b"MM"}:
        return "tiff"
    if data.startswith(b"%PDF"):
        return "pdf"
    if source_name and "." in source_name:
        extension = source_name.rsplit(".", 1)[-1].lower()
        if extension in {"jpg", "jpeg"}:
            return "jpeg"
        if extension == "png":
            return "png"
        if extension == "gif":
            return "gif"
        if extension == "bmp":
            return "bmp"
        if extension == "webp":
            return "webp"
        if extension in {"tif", "tiff"}:
            return "tiff"
        if extension == "pdf":
            return "pdf"
    return "unknown"

