def _average_rgb(raster: Raster) -> dict[str, int]:
    source = raster.to_rgb()
    pixel_count = len(source.data) // 3
    if pixel_count == 0:
        return {"r": 0, "g": 0, "b": 0}
    red = sum(source.data[index] for index in range(0, len(source.data), 3)) // pixel_count
    green = sum(source.data[index + 1] for index in range(0, len(source.data), 3)) // pixel_count
    blue = sum(source.data[index + 2] for index in range(0, len(source.data), 3)) // pixel_count
    return {"r": red, "g": green, "b": blue}

