def _dominant_colors(raster: Raster, limit: int = 5) -> list[dict[str, object]]:
    source = raster.to_rgb()
    pixel_count = source.width * source.height
    if pixel_count == 0:
        return []

    stride = max(1, pixel_count // 4096)
    counts: dict[tuple[int, int, int], int] = {}
    for pixel in range(0, pixel_count, stride):
        index = pixel * 3
        key = (
            source.data[index] // 32 * 32,
            source.data[index + 1] // 32 * 32,
            source.data[index + 2] // 32 * 32,
        )
        counts[key] = counts.get(key, 0) + 1

    total = sum(counts.values())
    ranked = sorted(counts.items(), key=lambda item: item[1], reverse=True)[:limit]
    colors: list[dict[str, object]] = []
    for (red, green, blue), count in ranked:
        colors.append(
            {
                "hex": f"#{red:02x}{green:02x}{blue:02x}",
                "rgb": [red, green, blue],
                "share": round(count / total, 4),
            }
        )
    return colors

