def _channel_ranges(raster: Raster) -> dict[str, dict[str, int]]:
    source = raster.to_rgb()
    reds: list[int] = []
    greens: list[int] = []
    blues: list[int] = []
    for index in range(0, len(source.data), 3):
        reds.append(source.data[index])
        greens.append(source.data[index + 1])
        blues.append(source.data[index + 2])
    if not reds:
        return {
            "r": {"min": 0, "max": 0},
            "g": {"min": 0, "max": 0},
            "b": {"min": 0, "max": 0},
        }
    return {
        "r": {"min": min(reds), "max": max(reds)},
        "g": {"min": min(greens), "max": max(greens)},
        "b": {"min": min(blues), "max": max(blues)},
    }

