def _build_summary(payload: dict[str, object]) -> str:
    parts = [
        f"{payload['filename']}",
        str(payload["format"]).upper(),
        f"{payload['width']}×{payload['height']}",
        f"{payload['byte_size']:,} bytes",
    ]
    if payload.get("has_alpha"):
        parts.append("alpha")
    exif = payload.get("exif")
    if isinstance(exif, dict) and exif.get("present"):
        orientation = exif.get("orientation_label") or exif.get("orientation")
        if orientation:
            parts.append(f"EXIF {orientation}")
        if exif.get("has_gps"):
            parts.append("GPS")
    return " · ".join(parts)
